  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'missing token' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET); // checks signature AND exp
    next();
  } catch (err) {
    return res.status(401).json({ error: 'invalid or expired token' }); // TokenExpiredError, etc.
  }
}
```

