## Pool configuration

```javascript
// db.js
const { Pool } = require('pg');

const pool = new Pool({
  host: process.env.PGHOST || 'localhost',
  port: process.env.PGPORT || 5432,
  database: process.env.PGDATABASE,
  user: process.env.PGUSER,
  password: process.env.PGPASSWORD,

  // --- Pool sizing ---
  max: 20,                       // max clients in pool
  min: 2,                        // keep a few warm (pg >= 8.10)

  // --- Timeouts (all in ms) ---
  connectionTimeoutMillis: 5000, // fail if can't get a connection in 5s
  idleTimeoutMillis: 30000,      // close idle clients after 30s
  maxLifetimeSeconds: 3600,      // recycle a client after 1h (pg >= 8.11)

  // --- Per-query server-side timeouts ---
  statement_timeout: 30000,      // kill any query running > 30s
  query_timeout: 30000,          // client-side query timeout
  idle_in_transaction_session_timeout: 60000, // kill idle-in-tx sessions

  // --- Keepalive (helps behind load balancers/NAT) ---
  keepAlive: true,
  keepAliveInitialDelayMillis: 10000,

  // --- TLS (managed providers like RDS/Supabase) ---
  ssl: process.env.PGSSL === 'true'
    ? { rejectUnauthorized: true, ca: process.env.PGSSL_CA }
    : false,
});

module.exports = pool;
```

